// Parse slash command: /doppelganger <event_name> <count> <source>
// Example: /doppelganger "TechConf 2026" 5 hubspot
const text = $input.first().json.body?.text || '';
const channelId = $input.first().json.body?.channel_id || '';
const userId = $input.first().json.body?.user_id || '';

// Parse arguments — supports quoted event names
const quotedMatch = text.match(/^"([^"]+)"\s+(\d+)?\s*(\w+)?$/);
const simpleMatch = text.match(/^(\S+)\s+(\d+)?\s*(\w+)?$/);

let eventName, personaCount, crmSource;

if (quotedMatch) {
  eventName = quotedMatch[1];
  personaCount = parseInt(quotedMatch[2] || '5', 10);
  crmSource = (quotedMatch[3] || 'sheets').toLowerCase();
} else if (simpleMatch) {
  eventName = simpleMatch[1];
  personaCount = parseInt(simpleMatch[2] || '5', 10);
  crmSource = (simpleMatch[3] || 'sheets').toLowerCase();
} else {
  eventName = text.trim() || 'Unnamed Event';
  personaCount = 5;
  crmSource = 'sheets';
}

// Clamp persona count to 3-10 range
personaCount = Math.max(3, Math.min(10, personaCount));

// Validate CRM source
const validSources = ['hubspot', 'salesforce', 'sheets'];
if (!validSources.includes(crmSource)) {
  crmSource = 'sheets';
}

return [{
  json: {
    eventName,
    personaCount,
    crmSource,
    channelId,
    userId,
    requestedAt: new Date().toISOString()
  }
}];

// Normalize audience data from any CRM source into a common format
const source = $('Parse Command Args').first().json.crmSource;
const items = $input.all();

let attendees = [];

if (source === 'hubspot') {
  const results = items[0]?.json?.results || items.map(i => i.json);
  attendees = results.map(r => ({
    name: [r.properties?.firstname, r.properties?.lastname].filter(Boolean).join(' ') || 'Unknown',
    title: r.properties?.jobtitle || '',
    company: r.properties?.company || '',
    industry: r.properties?.industry || '',
    location: [r.properties?.city, r.properties?.country].filter(Boolean).join(', ')
  }));
} else if (source === 'salesforce') {
  const records = items[0]?.json?.records || items.map(i => i.json);
  attendees = records.map(r => ({
    name: [r.FirstName, r.LastName].filter(Boolean).join(' ') || 'Unknown',
    title: r.Title || '',
    company: r.Account?.Name || '',
    industry: r.Account?.Industry || '',
    location: [r.MailingCity, r.MailingCountry].filter(Boolean).join(', ')
  }));
} else {
  // Google Sheets — expects columns: Name, Title, Company, Industry, Location
  attendees = items.map(i => ({
    name: i.json.Name || i.json.name || 'Unknown',
    title: i.json.Title || i.json.title || i.json['Job Title'] || '',
    company: i.json.Company || i.json.company || i.json.Organization || '',
    industry: i.json.Industry || i.json.industry || '',
    location: i.json.Location || i.json.location || i.json.City || ''
  }));
}

// Build audience summary for AI
const totalCount = attendees.length;
const titles = attendees.map(a => a.title).filter(Boolean);
const companies = attendees.map(a => a.company).filter(Boolean);
const industries = attendees.map(a => a.industry).filter(Boolean);

const titleCounts = {};
titles.forEach(t => { titleCounts[t] = (titleCounts[t] || 0) + 1; });
const industryCounts = {};
industries.forEach(i => { industryCounts[i] = (industryCounts[i] || 0) + 1; });

return [{
  json: {
    totalAttendees: totalCount,
    topTitles: Object.entries(titleCounts).sort((a,b) => b[1]-a[1]).slice(0, 15).map(([k,v]) => `${k} (${v})`).join(', '),
    topIndustries: Object.entries(industryCounts).sort((a,b) => b[1]-a[1]).slice(0, 10).map(([k,v]) => `${k} (${v})`).join(', '),
    uniqueCompanies: [...new Set(companies)].length,
    sampleAttendees: JSON.stringify(attendees.slice(0, 20), null, 2),
    eventName: $('Parse Command Args').first().json.eventName,
    personaCount: $('Parse Command Args').first().json.personaCount,
    crmSource: $('Parse Command Args').first().json.crmSource
  }
}];

// Parse the AI-generated persona JSON from the LLM response
const response = $input.first().json.text || $input.first().json.response || '';

// Extract JSON array from response (handle markdown code blocks)
let jsonStr = response;
const jsonMatch = response.match(/\[\s*\{[\s\S]*\}\s*\]/);
if (jsonMatch) {
  jsonStr = jsonMatch[0];
}

let personas;
try {
  personas = JSON.parse(jsonStr);
} catch (e) {
  // Try to fix common JSON issues
  jsonStr = jsonStr.replace(/,\s*\]/g, ']').replace(/,\s*\}/g, '}');
  personas = JSON.parse(jsonStr);
}

const eventName = $('Parse Command Args').first().json.eventName;
const channelId = $('Parse Command Args').first().json.channelId;
const crmSource = $('Parse Command Args').first().json.crmSource;

// Return each persona as a separate item for the loop
return personas.map((persona, index) => ({
  json: {
    ...persona,
    persona_index: index + 1,
    persona_total: personas.length,
    event_name: eventName,
    channel_id: channelId,
    crm_source: crmSource,
    persona_json: JSON.stringify(persona),
    created_at: new Date().toISOString()
  }
}));

// Build Slack Block Kit message for this persona
const p = $input.first().json;

const card = `${p.emoji || '🧬'} *Digital Doppelgänger #${p.persona_index}/${p.persona_total}*

*${p.persona_name}* — ${p.persona_title}
_${p.persona_org}_ (${p.org_size}) | ${p.industry}

🎯 *Motivation:* ${p.primary_motivation}

😤 *Pain Points:*
${(p.pain_points || []).map(pp => '  • ' + pp).join('\n')}

🧠 *Decision Style:* ${p.decision_style} | 💰 *Budget Authority:* ${p.budget_authority}

🤝 *Networking:* ${p.networking_preference}
📚 *Prefers:* ${(p.content_preferences || []).join(', ')}

⚠️ *Likely Objections:*
${(p.likely_objections || []).map(o => '  • ' + o).join('\n')}

📊 *Predicted Behavior:* ${p.engagement_prediction}

---
_💬 Reply in this thread to interview ${p.persona_name} — ask about their preferences, concerns, or what would make this event valuable to them._
_🧬 Synthetic persona generated from aggregate ${p.crm_source} data for "${p.event_name}"_`;

return [{
  json: {
    ...p,
    slackMessage: card
  }
}];

// Capture the Slack message timestamp for interview thread routing
const slackResponse = $input.first().json;
const threadTs = slackResponse.ts || slackResponse.message?.ts || '';
const personaData = $('Format Persona Card').first().json;

// We'll update the Data Table record with the thread_ts
// For now, store it for the summary
return [{
  json: {
    persona_name: personaData.persona_name,
    thread_ts: threadTs,
    channel_id: personaData.channel_id,
    persona_index: personaData.persona_index,
    persona_total: personaData.persona_total
  }
}];

// Format the auto-interview response for this persona
const interviewResponse = $input.first().json.text || $input.first().json.response || '';
const personaData = $('Parse Persona JSON').first().json;

const report = `🧬 *AUTO-INTERVIEW REPORT: ${personaData.persona_name}*
_${personaData.persona_title} at ${personaData.persona_org}_ (${personaData.org_size}) | ${personaData.industry}

${interviewResponse}

---
_${personaData.emoji || '🧬'} Digital Doppelgänger #${personaData.persona_index}/${personaData.persona_total} | Auto-interview for "${personaData.event_name}"_`;

return [{
  json: {
    report,
    persona_name: personaData.persona_name,
    persona_index: personaData.persona_index,
    persona_total: personaData.persona_total,
    channel_id: personaData.channel_id,
    event_name: personaData.event_name
  }
}];
